olid fa-floppy-disk"></i> Save Classes</button><a class="module-btn btn-muted-soft" href="teachers.php">Cancel</a></div></section></form></div></div></div><script>var s=document.getElementById('classSearch');s.addEventListener('input',function(){var q=this.value.toLowerCase();document.querySelectorAll('#classOptions .multi-option').forEach(function(o){o.style.display=o.textContent.toLowerCase().indexOf(q)>-1?'':'none';});});document.getElementById('assignmentForm').addEventListener('submit',function(e){e.preventDefault();document.getElementById('saveAlert').style.display='block';});</script><?php require_once('includes/footer.php'); ?>